jsLib:
var FQTT_BASE='https://fq-tt-worker.ch6vip.workers.dev';
var FQTT_BROWSER={isHideable:true,expandedCornersRadius:12,skipCollapsed:true,hardwareAccelerated:true,heightPercentage:0.8};
function fqGetQuery(url,name){var m=String(url||'').match(new RegExp('[?&]'+name+'=([^&#]*)'));return m&&m[1]?decodeURIComponent(m[1]):'';}
function fqFindQueryInText(text,names){var s=String(text||'');for(var i=0;i<names.length;i++){var re=new RegExp('(?:[?&]|\\b)'+names[i]+'=([0-9]{6,})','i');var m=s.match(re);if(m&&m[1])return m[1];}return '';}
function fqStringifyDeep(obj,depth){var out='';if(depth<0||obj===null||obj===undefined)return out;try{var t=typeof obj;if(t==='string'||t==='number'||t==='boolean')return ' '+obj;for(var k in obj){var v=obj[k];if(v===null||v===undefined)continue;var vt=typeof v;if(vt==='string'||vt==='number'||vt==='boolean')out+=' '+k+'='+v;else if(depth>0)out+=' '+k+' '+fqStringifyDeep(v,depth-1);}}catch(e){}return out;}
function fqCleanParagraphText(text){return String(text||'').replace(/<[^>]+>/g,'').replace(/&nbsp;/g,' ').replace(/&lt;/g,'<').replace(/&gt;/g,'>').replace(/&amp;/g,'&').replace(/^\s+|\s+$/g,'');}
function fqNormalizeTitleText(text){return fqCleanParagraphText(text).replace(/\s+/g,'');}
function fqLooksLocalChapterTitle(text,ctx){var v=fqNormalizeTitleText(text);if(!v||v.length>30)return false;var c=ctx&&ctx.chapter?ctx.chapter:{};var title=fqNormalizeTitleText(c.title||c.name||c.chapterName||c.chapterTitle||ctx.title||'');if(title&&(v===title||v.indexOf(title)>=0||title.indexOf(v)>=0))return true;return /^第[0-9零〇一二两三四五六七八九十百千万壹贰叁肆伍陆柒捌玖拾佰仟]{1,12}[章节卷回]/.test(v)||/^(序章|楔子|引子|尾声|后记|番外)/.test(v);}
function fqSplitLines(text){return String(text||'').replace(/\r/g,'').split('\n');}
function fqHasBubbleMarker(line,bookId,itemId,paraIndex){return String(line||'').indexOf('paragraphRule:fqtt:'+bookId+':'+itemId+':'+paraIndex)>=0;}
function fqCommentPageUrl(bookId,itemId,paraIndex){return FQTT_BASE+'/?api=comment_page&book_id='+encodeURIComponent(String(bookId||''))+'&item_id='+encodeURIComponent(String(itemId||''))+'&para_index='+encodeURIComponent(String(paraIndex||'0'))+'&offset=0&count=100';}
function showCmt(bookId,itemId,paraIndex,paraText){java.showBrowser(fqCommentPageUrl(bookId,itemId,paraIndex),null,null,JSON.stringify(FQTT_BROWSER));}
function fqMakeBubble(bookId,itemId,paraIndex,paraText){var p=String(paraIndex||'0');var click={style:'TEXT',type:'fq',status:'normal',pclick:'rule:'+ruleId+':showCmt('+JSON.stringify(String(bookId))+','+JSON.stringify(String(itemId))+','+JSON.stringify(p)+','+JSON.stringify(String(paraText||''))+')',marker:'paragraphRule:fqtt:'+bookId+':'+itemId+':'+p};return '<img src="dp:评,'+JSON.stringify(click)+'">';}

script:
function process(ctx){
  if(!ctx||!ctx.chapter)return ctx&&ctx.result?ctx.result:null;
  var meta=fqResolveChapterMeta(ctx);
  if(!meta||!meta.bookId||!meta.itemId){try{java.log('fqtt paragraph no bookId/itemId');}catch(e){} return ctx.result||ctx.content||ctx.paragraphs;}
  var lines=fqSplitLines(String(ctx.content||ctx.result||''));
  var localIndex=0;
  var firstText=true;
  var hits=0;
  for(var i=0;i<lines.length;i++){
    var line=String(lines[i]||'');
    var text=fqCleanParagraphText(line);
    if(!text)continue;
    if(firstText&&fqLooksLocalChapterTitle(text,ctx)){firstText=false;continue;}
    firstText=false;
    var idx=String(localIndex++);
    if(fqHasBubbleMarker(line,meta.bookId,meta.itemId,idx))continue;
    lines[i]=line+fqMakeBubble(meta.bookId,meta.itemId,idx,text);
    hits++;
  }
  try{java.log('fqtt paragraph bubbles='+hits+' bookId='+meta.bookId+' itemId='+meta.itemId);}catch(e){}
  return lines.join('\n');
}
function fqResolveChapterMeta(ctx){
  try{
    var chapter=ctx.chapter||{};
    var book=ctx.book||{};
    var urls=[String(chapter.url||''),String(chapter.chapterUrl||''),String(ctx.baseUrl||''),String(ctx.url||''),String(ctx.chapterUrl||''),String(book.bookUrl||''),String(book.url||'')];
    var scanText=urls.join(' ')+' '+fqStringifyDeep(ctx,3)+' '+fqStringifyDeep(chapter,3)+' '+fqStringifyDeep(book,3);
    var itemId='';
    var itemKeys=['item_ids','item_id','itemId','itemid'];
    for(var i=0;i<itemKeys.length&&!itemId;i++)itemId=fqGetQuery(urls.join('&'),itemKeys[i]);
    if(!itemId)itemId=fqFindQueryInText(scanText,itemKeys);
    if(itemId&&itemId.indexOf(',')>=0)itemId=itemId.split(',')[0];
    var bookId=fqGetQuery(urls.join('&'),'book_id')||fqGetQuery(urls.join('&'),'bookId')||fqGetQuery(urls.join('&'),'bookid')||fqFindQueryInText(scanText,['book_id','bookid','bookId']);
    return {bookId:String(bookId||''),itemId:String(itemId||'')};
  }catch(e){try{java.log('fqtt paragraph meta failed: '+e);}catch(_e){} return null;}
}
